svg.script:

var SVG_NS = 'http://www.w3.org/2000/svg';
var scene = document.getElementById('scene');

var COLOR_DIM = '#0d4a5a';
var COLOR_BASE = '#1a7a8f';
var COLOR_BRIGHT = '#3aeaf5';
var COLOR_WHITE = '#b0f4ff';

// ── Tree geometry ──────────────────────────────────────────────

var leftTreeNodes = [
  {x:370, y:175},  // 0 peak
  {x:310, y:215},  // 1
  {x:380, y:205},  // 2
  {x:445, y:220},  // 3
  {x:255, y:265},  // 4
  {x:325, y:255},  // 5
  {x:395, y:248},  // 6
  {x:468, y:265},  // 7
  {x:225, y:318},  // 8
  {x:288, y:305},  // 9
  {x:355, y:295},  // 10
  {x:425, y:305},  // 11
  {x:498, y:320},  // 12
  {x:205, y:372},  // 13
  {x:268, y:358},  // 14
  {x:338, y:345},  // 15
  {x:408, y:350},  // 16
  {x:478, y:365},  // 17
  {x:540, y:382},  // 18
  {x:228, y:418},  // 19
  {x:298, y:408},  // 20
  {x:368, y:400},  // 21
  {x:438, y:408},  // 22
  {x:508, y:420},  // 23
  {x:258, y:458},  // 24
  {x:328, y:448},  // 25
  {x:388, y:442},  // 26
  {x:455, y:450},  // 27
  {x:518, y:462},  // 28
  {x:298, y:488},  // 29
  {x:368, y:482},  // 30
  {x:438, y:488},  // 31
  // Trunk nodes
  {x:365, y:540},  // 32
  {x:375, y:540},  // 33
  {x:358, y:650},  // 34
  {x:382, y:650},  // 35
  {x:352, y:760},  // 36
  {x:388, y:760},  // 37
];

var leftTreeEdges = [
  // Peak connections
  [0,1],[0,2],[0,3],[1,2],[2,3],
  // Row 2
  [1,4],[1,5],[2,5],[2,6],[3,6],[3,7],[4,5],[5,6],[6,7],
  // Row 3
  [4,8],[4,9],[5,9],[5,10],[6,10],[6,11],[7,11],[7,12],[8,9],[9,10],[10,11],[11,12],
  // Row 4
  [8,13],[8,14],[9,14],[9,15],[10,15],[10,16],[11,16],[11,17],[12,17],[12,18],[13,14],[14,15],[15,16],[16,17],[17,18],
  // Row 5
  [13,19],[14,19],[14,20],[15,20],[15,21],[16,21],[16,22],[17,22],[17,23],[18,23],[19,20],[20,21],[21,22],[22,23],
  // Row 6
  [19,24],[20,24],[20,25],[21,25],[21,26],[22,26],[22,27],[23,27],[23,28],[24,25],[25,26],[26,27],[27,28],
  // Row 7
  [24,29],[25,29],[25,30],[26,30],[27,30],[27,31],[28,31],[29,30],[30,31],
  // Trunk
  [30,32],[30,33],[29,32],[31,33],[32,34],[33,35],[34,36],[35,37],
  // Cross-row diagonals for depth
  [4,10],[5,11],[9,15],[10,16],[14,21],[15,22],[20,26],[21,27],[25,30],[26,31],
];

// Right tree — mirror of left, shifted right with slight variation
var rightTreeNodes = leftTreeNodes.map(function(n) {
  return {x: 1600 - n.x + 20, y: n.y + 8};
});
var rightTreeEdges = leftTreeEdges.slice();

// Small trees between the big ones
var smallTrees = [
  { // Tree 1
    nodes: [
      {x:620, y:580}, {x:610, y:540}, {x:630, y:535}, {x:600, y:500},
      {x:625, y:490}, {x:648, y:505}, {x:618, y:465}, {x:640, y:470},
      {x:620, y:670}, {x:625, y:760}
    ],
    edges: [[0,1],[0,2],[1,2],[1,3],[1,4],[2,4],[2,5],[3,4],[4,5],[3,6],[4,6],[4,7],[5,7],[6,7],[0,8],[8,9]]
  },
  { // Tree 2
    nodes: [
      {x:730, y:595}, {x:720, y:555}, {x:742, y:548}, {x:710, y:515},
      {x:735, y:505}, {x:755, y:520}, {x:728, y:478}, {x:748, y:485},
      {x:732, y:680}, {x:735, y:760}
    ],
    edges: [[0,1],[0,2],[1,2],[1,3],[1,4],[2,4],[2,5],[3,4],[4,5],[3,6],[4,6],[4,7],[5,7],[6,7],[0,8],[8,9]]
  },
  { // Tree 3 (center, slightly taller)
    nodes: [
      {x:830, y:575}, {x:818, y:530}, {x:842, y:525}, {x:808, y:488},
      {x:833, y:478}, {x:855, y:492}, {x:822, y:448}, {x:845, y:455},
      {x:832, y:418}, {x:830, y:665}, {x:833, y:760}
    ],
    edges: [[0,1],[0,2],[1,2],[1,3],[1,4],[2,4],[2,5],[3,4],[4,5],[3,6],[4,6],[4,7],[5,7],[6,7],[6,8],[7,8],[0,9],[9,10]]
  },
  { // Tree 4
    nodes: [
      {x:940, y:590}, {x:930, y:550}, {x:952, y:545}, {x:920, y:510},
      {x:942, y:500}, {x:962, y:515}, {x:935, y:472}, {x:955, y:478},
      {x:938, y:675}, {x:942, y:760}
    ],
    edges: [[0,1],[0,2],[1,2],[1,3],[1,4],[2,4],[2,5],[3,4],[4,5],[3,6],[4,6],[4,7],[5,7],[6,7],[0,8],[8,9]]
  },
  { // Tree 5
    nodes: [
      {x:1040, y:585}, {x:1030, y:545}, {x:1052, y:540}, {x:1020, y:505},
      {x:1045, y:495}, {x:1065, y:510}, {x:1038, y:468}, {x:1058, y:475},
      {x:1042, y:672}, {x:1045, y:760}
    ],
    edges: [[0,1],[0,2],[1,2],[1,3],[1,4],[2,4],[2,5],[3,4],[4,5],[3,6],[4,6],[4,7],[5,7],[6,7],[0,8],[8,9]]
  }
];

// ── Rendering ──────────────────────────────────────────────────

function createEl(tag, attrs) {
  var el = document.createElementNS(SVG_NS, tag);
  for (var k in attrs) {
    if (attrs.hasOwnProperty(k)) el.setAttribute(k, attrs[k]);
  }
  return el;
}

function drawTree(nodes, edges, opacity) {
  var g = createEl('g', {'filter': 'url(#glow)', 'opacity': opacity || '1'});
  var edgeEls = [];
  var nodeEls = [];

  // Draw edges
  edges.forEach(function(e) {
    var a = nodes[e[0]], b = nodes[e[1]];
    var line = createEl('line', {
      x1: a.x, y1: a.y, x2: b.x, y2: b.y,
      stroke: COLOR_DIM, 'stroke-width': '1.2', 'stroke-linecap': 'round'
    });
    g.appendChild(line);
    edgeEls.push({el: line, from: e[0], to: e[1]});
  });

  // Draw nodes
  nodes.forEach(function(n, i) {
    var circle = createEl('circle', {
      cx: n.x, cy: n.y, r: '2.2',
      fill: COLOR_BASE, opacity: '0.9'
    });
    g.appendChild(circle);
    nodeEls.push(circle);
  });

  scene.appendChild(g);
  return {group: g, edges: edgeEls, nodes: nodeEls, data: nodes};
}

var treesRendered = [];
treesRendered.push(drawTree(leftTreeNodes, leftTreeEdges, '1'));
treesRendered.push(drawTree(rightTreeNodes, rightTreeEdges, '1'));
smallTrees.forEach(function(t) {
  treesRendered.push(drawTree(t.nodes, t.edges, '0.7'));
});

// ── Particle animation ─────────────────────────────────────────

var particles = [];
var PARTICLE_POOL_SIZE = 18;

function spawnParticle() {
  // Pick a random tree and edge
  var treeIdx = Math.floor(Math.random() * treesRendered.length);
  // Weight toward the big trees
  if (Math.random() < 0.65) treeIdx = Math.random() < 0.5 ? 0 : 1;

  var tree = treesRendered[treeIdx];
  var edgeIdx = Math.floor(Math.random() * tree.edges.length);
  var edge = tree.edges[edgeIdx];
  var fromNode = tree.data[edge.from];
  var toNode = tree.data[edge.to];

  // Sometimes reverse direction
  if (Math.random() < 0.5) {
    var tmp = fromNode;
    fromNode = toNode;
    toNode = tmp;
    var tmpIdx = edge.from;
    edge = {el: edge.el, from: edge.to, to: tmpIdx};
  }

  var dx = toNode.x - fromNode.x;
  var dy = toNode.y - fromNode.y;
  var dist = Math.sqrt(dx * dx + dy * dy);
  var duration = dist * 12 + 400; // ms, proportional to distance

  var particleEl = createEl('circle', {
    cx: fromNode.x, cy: fromNode.y, r: '2.5',
    fill: COLOR_BRIGHT, opacity: '0.9', filter: 'url(#particle-glow)'
  });
  scene.appendChild(particleEl);

  return {
    el: particleEl,
    fromX: fromNode.x, fromY: fromNode.y,
    toX: toNode.x, toY: toNode.y,
    edgeEl: edge.el,
    toNodeEl: tree.nodes[edge.to !== undefined ? edge.to : 0],
    startTime: performance.now() + Math.random() * 500,
    duration: duration,
    treeIdx: treeIdx,
    alive: true
  };
}

// Initialize particles with staggered starts
for (var i = 0; i < PARTICLE_POOL_SIZE; i++) {
  var p = spawnParticle();
  p.startTime = performance.now() + i * 350 + Math.random() * 600;
  particles.push(p);
}

// Node pulse state
var pulsingNodes = [];

function pulseNode(nodeEl) {
  pulsingNodes.push({
    el: nodeEl,
    startTime: performance.now(),
    duration: 400
  });
}

function animate(now) {
  // Update particles
  particles.forEach(function(p, idx) {
    if (!p.alive) return;

    var elapsed = now - p.startTime;
    if (elapsed < 0) {
      p.el.setAttribute('opacity', '0');
      return;
    }

    var t = elapsed / p.duration;
    if (t >= 1) {
      // Particle reached destination — pulse the node
      pulseNode(p.toNodeEl);

      // Briefly brighten the edge
      p.edgeEl.setAttribute('stroke', COLOR_BRIGHT);
      p.edgeEl.setAttribute('stroke-width', '2');
      setTimeout(function(el) {
        return function() {
          el.setAttribute('stroke', COLOR_DIM);
          el.setAttribute('stroke-width', '1.2');
        };
      }(p.edgeEl), 300);

      // Recycle particle
      scene.removeChild(p.el);
      var newP = spawnParticle();
      newP.startTime = now + 200 + Math.random() * 1500;
      particles[idx] = newP;
      return;
    }

    // Ease in-out for smooth motion
    var easedT = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;

    var cx = p.fromX + (p.toX - p.fromX) * easedT;
    var cy = p.fromY + (p.toY - p.fromY) * easedT;

    p.el.setAttribute('cx', cx);
    p.el.setAttribute('cy', cy);
    p.el.setAttribute('opacity', 0.6 + 0.4 * Math.sin(t * Math.PI));

    // Brighten the edge the particle is on
    var brightness = 0.3 + 0.7 * Math.sin(t * Math.PI);
    p.edgeEl.setAttribute('stroke', lerpColor(COLOR_DIM, COLOR_BASE, brightness));
  });

  // Update pulsing nodes
  for (var j = pulsingNodes.length - 1; j >= 0; j--) {
    var pn = pulsingNodes[j];
    var pt = (now - pn.startTime) / pn.duration;
    if (pt >= 1) {
      pn.el.setAttribute('r', '2.2');
      pn.el.setAttribute('fill', COLOR_BASE);
      pn.el.setAttribute('opacity', '0.9');
      pulsingNodes.splice(j, 1);
      continue;
    }
    // Pulse: expand radius and brighten
    var pulseAmount = Math.sin(pt * Math.PI);
    var r = 2.2 + 2.8 * pulseAmount;
    pn.el.setAttribute('r', r);
    pn.el.setAttribute('fill', lerpColor(COLOR_BASE, COLOR_WHITE, pulseAmount));
    pn.el.setAttribute('opacity', String(0.9 + 0.1 * pulseAmount));
  }

  requestAnimationFrame(animate);
}

function lerpColor(a, b, t) {
  var ar = parseInt(a.slice(1,3), 16), ag = parseInt(a.slice(3,5), 16), ab = parseInt(a.slice(5,7), 16);
  var br = parseInt(b.slice(1,3), 16), bg = parseInt(b.slice(3,5), 16), bb = parseInt(b.slice(5,7), 16);
  var rr = Math.round(ar + (br - ar) * t);
  var rg = Math.round(ag + (bg - ag) * t);
  var rb = Math.round(ab + (bb - ab) * t);
  return '#' + ((1 << 24) + (rr << 16) + (rg << 8) + rb).toString(16).slice(1);
}

// Ambient subtle pulse on all nodes (very gentle)
treesRendered.forEach(function(tree) {
  tree.nodes.forEach(function(nodeEl, i) {
    var delay = Math.random() * 8000;
    var dur = 4000 + Math.random() * 3000;
    (function pulse(el, d, dur) {
      setTimeout(function() {
        var start = performance.now();
        function ambientPulse(now) {
          var t = ((now - start) % dur) / dur;
          var v = 0.05 * Math.sin(t * 2 * Math.PI);
          el.setAttribute('r', String(2.2 + v));
          el.setAttribute('opacity', String(0.85 + 0.15 * Math.sin(t * 2 * Math.PI)));
          requestAnimationFrame(ambientPulse);
        }
        requestAnimationFrame(ambientPulse);
      }, d);
    })(nodeEl, delay, dur);
  });
});

requestAnimationFrame(animate);
